const traverse = require('@babel/traverse').default;
const babelTypes = require('@babel/types');

const { APP_FILE_MEMBERS } = require('../../../constants/file');
const { NordicIslandsError } = require('../../../error/nordic-islands-error');
const { astCache } = require('../../../cache/ast-cache');
const { normalizeIslandClientName } = require('../../../helpers/normalizers');
const {
  getIslandChildCallExpressionWithoutDisplaynameError,
  getForwardRefIslandWithoutNameError,
  getForwardRefIslandNotDefinedLocallyError,
} = require('../../../error/get-discovery-error');

/**
 * @typedef {Object} CompleteComponentInfo
 * @property {string} name
 * @property {string} exportedName
 * @property {string} path
 * @property {boolean} namedExport
 * @property {boolean} shouldUseDisplayName
 * @property {import('../../../helpers/forward-ref').ForwardRefInfo} forwardRefInnerFn
 */

// TODO: Remove forwardRefInnerFn use when "forwardRef" support is removed
/**
 * @param {CompleteComponentInfo} componentInfo
 * @returns {import('../../../helpers/file-system/islands-manifest').IslandsManifest}
 */
const getCompleteIslandChild = ({
  name,
  exportedName,
  path,
  namedExport,
  shouldUseDisplayName,
  forwardRefInnerFn,
}) => {
  let displayName = null;

  const ast = astCache.getAstByFilePath(path);

  traverse(ast, {
    noScope: true,
    AssignmentExpression(babelPath) {
      if (
        !babelTypes.isMemberExpression(babelPath.node.left) ||
        !babelTypes.isLiteral(babelPath.node.right) ||
        !babelTypes.isIdentifier(babelPath.node.left.object) ||
        babelPath.node.left.object.name !== name ||
        !babelTypes.isIdentifier(babelPath.node.left.property) ||
        babelPath.node.left.computed ||
        babelPath.node.left.property.name !== 'displayName'
      ) {
        return;
      }

      displayName = babelPath.node.right.value;
      babelPath.stop();
    },
  });

  if (forwardRefInnerFn.name && !forwardRefInnerFn.isLocal) {
    throw new NordicIslandsError(
      getForwardRefIslandNotDefinedLocallyError(name),
      {
        type: APP_FILE_MEMBERS.COMPONENT,
        path,
      },
    );
  }

  if (shouldUseDisplayName && !displayName) {
    throw new NordicIslandsError(
      typeof forwardRefInnerFn.name === 'string'
        ? getForwardRefIslandWithoutNameError(name)
        : getIslandChildCallExpressionWithoutDisplaynameError(name),
      {
        type: APP_FILE_MEMBERS.COMPONENT,
        path,
      },
    );
  }

  const islandClient = normalizeIslandClientName(path);

  return {
    [islandClient]: {
      exportName: namedExport ? exportedName : forwardRefInnerFn.name || name,
      name: displayName || forwardRefInnerFn.name || name,
      path,
      namedExport,
    },
  };
};

module.exports = {
  getCompleteIslandChild,
};
